head.script:
scwin.strFromDate;
scwin.memJson;
scwin.privAdmin;

scwin.wrkNo;
scwin.fromDate;
scwin.vLoginCoCd;
scwin.vLoginCoClsCd;
scwin.vUserHomeClsCd;
scwin.isSubCompany;

scwin.udc_objNm;
scwin.udc_select_code;

scwin.rtnFlag;
scwin.interval01;


scwin.onpageload = function() {
	//전역변수값 셋팅함수.
	scwin.initSetVal();

    lc_acctDeptCd.setDisabled(true);
};


scwin.initSetVal = function() {
    scwin.strFromDate = WebSquare.date.getCurrentServerDate().substring(0, 6);
    scwin.memJson = $c.data.getMemInfo();
    scwin.privAdmin = scwin.memJson.privAdmin;

    scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // 소속 자회사
    scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;  //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd; // 사용자소속구분코드 
    scwin.isSubCompany = false;

    scwin.rtnFlag = false;
};

//udc 컴포넌트 onload 완료시...
scwin.onUdcCompleted = async function() {
    await scwin.f_CloseYm();
    await scwin.f_LoadVer();
    await scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    var iCnt = 0;
	// 필수조건 확인
    let ret = await $c.gus.cfValidate([ica_stdYm,acb_version,ed_acctDeptCd, ed_coCd]);
    if (!ret) {
        return;
    }

	if ( !((ed_acctCdFrom.getValue() == null) ||  (ed_acctCdFrom.getValue() == "")) ){
		iCnt = iCnt + 1;
	}

	if ( !((ed_acctCdTo.getValue() == null) ||  (ed_acctCdTo.getValue() == "")) ){
		iCnt = iCnt + 1;
	}

	if ( iCnt == 1){
		await $c.win.alert("계정코드from과 계정코드To를 함께 입력하십시오.");
		return false;
	}

    //ds_aggregation

    //dma_condition.set("acctDept", ed_acctDeptCd.getValue());
    //dma_condition.set("mgntAcctCd", ed_acctCdFrom.getValue());
    //dma_condition.set("mgntQtyAcctCd", ed_acctCdTo.getValue());
    dma_condition.set("lowerDeptIncluYn", cbx_lowerDeptIncluYn.getValue());



    dma_condition.set("distYn", "0");
    dma_condition.set("dpctYn", 0);
    dma_condition.set("exceptionDeptYn", 0);
    dma_condition.set("incluYn", "0");

    ds_aggregation_org.removeAll();
    ds_aggregation.removeAll();

    //submit 처리.
    let searchSubmit = await $c.sbm.execute(sbm_search);

    if(searchSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_search_submitdone();
    }
};

scwin.sbm_search_submitdone = async function (e) {
    for(var i=0;i<ds_aggregation_org.getRowCount();i++) {
        var totVal01 = Number(ds_aggregation_org.getCellData(i, "thisPlanAmt"));
        var totVal02 = Number(ds_aggregation_org.getCellData(i, "thisRsltsAmt"));
        var totVal03 = Number(ds_aggregation_org.getCellData(i, "bfyyThisAmt"));
        ds_aggregation_org.setCellData(i, "thisSilJeok", totVal01+totVal02-totVal03);
    }
    ds_aggregation_org.reform();

    ds_aggregation.setJSON(ds_aggregation_org.getAllJSON());
    ds_aggregation.reform();

    for(var i=0;i<ds_aggregation.getRowCount();i++) {
        /*
        ds_aggregation.setIgnoreStatus(true); 

        var totVal01 = Number(ds_aggregation.getCellData(i, "thisPlanAmt"));
        var totVal02 = Number(ds_aggregation.getCellData(i, "thisRsltsAmt"));
        var totVal03 = Number(ds_aggregation.getCellData(i, "bfyyThisAmt"));
        ds_aggregation.setCellData(i, "thisSilJeok", totVal01+totVal02-totVal03);

        ds_aggregation.setIgnoreStatus(false); 
        */

        if(totVal03 == 0) {
            gr_aggregation.setCellClass(i, "bfyyThisAmt", "cur-df");
        }

        if(totVal01 == 0) {
            gr_aggregation.setCellClass(i, "thisPlanAmt", "cur-df");
        }

        if(totVal02 == 0) {
            gr_aggregation.setCellClass(i, "thisRsltsAmt", "cur-df");
        }
    }

    //subsum row 갯수

    var nTotalCnt = gr_aggregation.getSubtotalRowList()[0];
    //totalRows.setValue(ds_aggregation.getRowCount()+nTotalCnt);
    totalRows.setValue(ds_aggregation.getRowCount());

	if(ds_aggregation.getRowCount() == 0 ){
		await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        lc_acctDeptCd.setDisabled(true);
	} else{
        lc_acctDeptCd.setDisabled(false);
	}
};


//-------------------------------------------------------------------------
// 마지막 마감년월를 구한다.
//-------------------------------------------------------------------------
scwin.f_CloseYm = async function () {
    /*
    var ebcId = "ManagementProfitAndLossEBC";
    var queryId = "retrieveManagementProfitAndLossCloseYm";
    ds_closeYm.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd="+ebcId +
                                            "&queryId="+queryId +
                                            "&param3="+ed_coCd.Text.trim();

    ds_closeYm.Reset();

    ed_stdYm.Text = ds_closeYm.NameValue(1,"col1");
    */
    dma_closeYm.set("sysCd", "ManagementProfitAndLossEBC");
    dma_closeYm.set("queryId", "retrieveManagementProfitAndLossCloseYm");
 	dma_closeYm.set("param3", ed_coCd.getValue().trim());	// 회사코드

    ds_closeYm.removeAll();

    //submit 처리.
    let closeYmSubmit = await $c.sbm.execute(sbm_closeYm);

    if(closeYmSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_closeYm_submitdone();
    }
};

scwin.sbm_closeYm_submitdone = async function (e) {
    ica_stdYm.setValue(ds_closeYm.getCellData(0, "col1"));
};

//-------------------------------------------------------------------------
// Ver정보를 가져온다.
//-------------------------------------------------------------------------
scwin.f_LoadVer = async function () {
    /*
    ds_version.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
												"&queryId=retrieveVersionInfo" +
												"&param1=" + ed_stdYm.Text.trim();
	ds_version.Reset();
    */

    dma_version.set("sysCd", "CommonEBC");
    dma_version.set("queryId", "retrieveVersionInfo");
 	dma_version.set("param1", ica_stdYm.getValue().trim());

    ds_version.removeAll();

    //submit 처리.
    let versionSubmit = await $c.sbm.execute(sbm_version);

    if(versionSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_version_submitdone();
    }
};

scwin.sbm_version_submitdone = async function (e) {
    scwin.f_SetFinalVer();
};

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function () {
    if (ds_version.getRowCount() < 1) {
        return;
    }

	var index = 0;
	for (let i = 0; i < ds_version.getRowCount(); i++) {  
		if (ds_version.getCellData(i, "col3") == DGlobalValue.TRUE) {
			index = i;
			break;
		}
	}

    acb_version.setSelectedIndex(index);
};

//-------------------------------------------------------------------------
// 실적부서를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetRsltsDept = async function () {
    let ret = await $c.gus.cfValidate([tbl_table1]);
    if (!ret) {
        return;
    }

    /*
    ds_dept.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=ManagementProfitAndLossEBC" +
                    "&queryId=retrievePlanComparisonResultsAcctDept" +
                    "&param1=" + ds_condition.NameValue(ds_condition.RowPosition,"acctDept") +
                    "&param2=" + ds_condition.NameValue(ds_condition.RowPosition,"closeYm") +
                    "&param3=" + ds_condition.NameValue(ds_condition.RowPosition,"lowerDeptIncluYn") +
                    "&param4=" + ds_condition.NameValue(ds_condition.RowPosition,"acctDeptLvl") +
                    "&param5=" + ds_condition.NameValue(ds_condition.RowPosition,"ver") + 
                    "&param7=" + ed_coCd.text;
    ds_dept.Reset();
    */

    dma_dept.set("sysCd", "ManagementProfitAndLossEBC"); 
    dma_dept.set("queryId", "retrievePlanComparisonResultsAcctDept");
    dma_dept.set("param1", ed_acctDeptCd.getValue());
    dma_dept.set("param2", ica_stdYm.getValue());

    //dma_dept.set("param3", dma_condition.get("lowerDeptIncluYn"));
    dma_dept.set("param3", cbx_lowerDeptIncluYn.getValue());

    dma_dept.set("param4", dma_condition.get("acctDeptLvl"));				
    dma_dept.set("param5", acb_version.getValue());					 
    dma_dept.set("param7", ed_coCd.getValue());

    ds_dept.removeAll();

    //submit 처리.
    let deptSubmit = await $c.sbm.execute(sbm_dept);

    if(deptSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_dept_submitdone();
    }
};

scwin.sbm_dept_submitdone = async function (e) {
    if (ds_dept.getRowCount() < 1) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    	return;
    }
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:검색->관리부서 , 2:검색->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp  = async function (callObj, select_code,txtCode,txtName,sFlag) {
	var sCmdName = "";
	var code = txtCode.getValue();
	var name = txtName.getValue();

    scwin.udc_objNm = callObj.org_id;
    scwin.udc_select_code = select_code;

  	switch (select_code) {
		// 관리부서 PopUp 호출
  		case '1' :
  			var pWhere = ica_stdYm.getValue()+",,,,,,,,,"+ed_coCd.getValue();
			sCmdName = "retrieveAcctDeptCdInfo";
            callObj.setSelectId(sCmdName);
			await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
                                        //sCmdName,
                                        code,name,sFlag,
                                        null,null,null,null,pWhere,null,null,null,null,null,null,null,null); // 관리부서

            break;

  		// 거래처 PopUp 호출
  		case '2' :
			sCmdName = "retrieveClntList"
            callObj.setSelectId(sCmdName);
			await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
                                        //sCmdName,
                                        code,name,sFlag,
                                        null,null,null,null,null,null,null,null,null,null,"F",null,null); // 거래처
		 	break;

  		// 계정코드 PopUp 호출
  		case '3' :
            var param = ",,,,,01";
            sCmdName = "retrieveAcctCdInfo";
            callObj.setSelectId(sCmdName);

            await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc,
                                        //sCmdName,
                                        code,name,sFlag,
                                        null,null,null,null,param,null,null,null,null,null,null,null,null); // 계정코드
		 	break;
	}
};


scwin.udc_AllInOne_callBackFunc = function (rtnList) {

    let codeObj;
    let nameObj;

    if(scwin.udc_objNm == "udc_acctDeptCd") {
        codeObj = ed_acctDeptCd;
        nameObj = ed_acctDeptNm;
    } else if(scwin.udc_objNm == "udc_acctCdFrom") {
        codeObj = ed_acctCdFrom;
        nameObj = ed_acctCdFromNm;
    } else if(scwin.udc_objNm == "udc_acctCdTo") {
        codeObj = ed_acctCdTo;
        nameObj = ed_acctCdToNm;
    }

    if ( rtnList != null ) {
		if (rtnList[0] == "N/A") {
            return;
        }

		codeObj.setValue(rtnList[0]);	// 코드
		nameObj.setValue(rtnList[1]);	// 코드명

        //to-do
		//txtCode.hidVal = rtnList[0];	// 코드

		if (scwin.udc_select_code == '1'){
           dma_condition.set("acctDeptLvl", rtnList[6]);                                      
		}

	} else {
        codeObj.setValue("");	// 코드
		nameObj.setValue("");	// 코드명

        //to-do
        //txtCode.hidVal = "";	// 코드
	}
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = async function (callObj, orgObjCd, orgObjNm,select_code) {
    /*
    if (orgObjCd.tagName.toUpperCase() == "INPUT" ) {
		if (orgObjCd.value != orgObjCd.hidVal){
			orgObjNm.value = "";
		}

		if (orgObjCd.value.trim() != "" ) {
			f_openPopUp(select_code,orgObjCd,orgObjNm,"T")
		} else {
			if (!orgObjNm == null)
			{
				orgObjNm.value = "";
			}
			orgObjCd.value = "";
			orgObjCd.hidVal = "";
		}
	}

    //로직상 하기만 타고 상위로직은 안탐.
	else if (orgObjCd.tagName.toUpperCase() == "OBJECT" ) {
		if (orgObjCd.Text != orgObjCd.hidVal){
			orgObjNm.value = "";
		}

		if (orgObjCd.Text.trim() != "") {
			f_openPopUp(select_code,orgObjCd,orgObjNm,"T");
		} else {
			if (!orgObjNm == null)
			{
				orgObjNm.Text = "";
			}
			orgObjCd.Text = "";
		}
	}
    */

    if (orgObjCd.getValue().trim() != "") {
        await scwin.f_openPopUp(callObj, select_code,orgObjCd,orgObjNm,"T");
    } else {
        if (orgObjNm.getValue() != undefined || orgObjNm.getValue() != null || orgObjNm.getValue() != "")
        {
            orgObjNm.setValue("");
        }
        orgObjCd.setValue("");
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_detail = async function (rowIdx, flag,addMonth) {
    if ( ds_aggregation.getRowCount() <= 0) {
		await $c.win.alert("계정별원가집계내역이 존재하지 않습니다.");
		return false;
	}

	var closeYm = ds_aggregation.getCellData(rowIdx, "closeYm")+""+"01";

	//var yearMonth     = closeYm.toDate().before(0,addMonth,0).format("YYYYMM");
    var yearMonth = $c.date.addMonth(closeYm, addMonth);
    yearMonth = yearMonth.substr(0,6);

	var acctDeptCd = ds_aggregation.getCellData(rowIdx, "acctDeptCd");
	var acctDeptNm = ds_aggregation.getCellData(rowIdx, "acctDeptCdNm");
	var acctCd = ds_aggregation.getCellData(rowIdx, "mgntAcctCd");
	var acctNm = ds_aggregation.getCellData(rowIdx, "mgntAcctCdNm");
	var coCd = ed_coCd.getValue();

	if ( flag == "1") {
        /*
		var style = "center:yes; dialogwidth:980px; dialogheight:730px; scroll:no; resizable:no; status:yes;";
		var strPath = "/ac/fi/gnrlaccount/slipmgnt/fi_201_04_05p.jsp?closeYm="+yearMonth.trim()
				+"&acctDeptCd="+acctDeptCd.trim()+"&acctDeptNm="+acctDeptNm.trim()+"&acctCd="+acctCd.trim()+"&acctNm="+acctNm.trim();
		var returnValue = window.showModalDialog(strPath, ds_aggregation ,style ) ;
        */

        var data = {
            closeYm:yearMonth.trim(),
            acctDeptCd:acctDeptCd.trim(),
            acctDeptNm:acctDeptNm.trim(),
            acctCd:acctCd.trim(),
            acctNm:acctNm.trim()
        };

        var opts = {
            id : "smpPop", 
            popupName : "전표상세내역", //  팝업 타이틀에 표시
            type : "browserPopup"  // window popup , 해당 옵션이 없으면 layer popup
            ,modal : true
            , width : 1240
            , height : 600
        };

        let returnValue = await $c.win.openPopup("/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_04_05p.xml", opts, data);

        //to-do 불필요??
        //$c.gus.cfSetReturnValue(returnValue, ds_aggregation);
	} else {
        /*
		var style = "center:yes; dialogwidth:980px; dialogheight:730px; scroll:no; resizable:no; status:yes;";
		var strPath = "/ac/fi/gnrlaccount/settmgnt/fi_204_02_04p.jsp?closeYm="+yearMonth.trim()
				+"&acctDeptCd="+acctDeptCd.trim()+"&acctDeptNm="+acctDeptNm.trim()+"&acctCd="+acctCd.trim()+"&acctNm="+acctNm.trim();
		var returnValue = window.showModalDialog(strPath, ds_aggregation ,style ) ;
        */

        var data = {
            closeYm:yearMonth.trim(),
            acctDeptCd:acctDeptCd.trim(),
            acctDeptNm:acctDeptNm.trim(),
            acctCd:acctCd.trim(),
            acctNm:acctNm.trim()
        };

        var opts = {
            id : "smpPop", 
            popupName : "조정전표상세내역", //  팝업 타이틀에 표시
            type : "browserPopup"  // window popup , 해당 옵션이 없으면 layer popup
            ,modal : true
            , width : 1240
            , height : 600
        };

        let returnValue = await $c.win.openPopup("/ui/ac/fi/gnrlaccount/settmgnt/fi_204_02_04p.xml", opts, data);

        //to-do 불필요??
        //$c.gus.cfSetReturnValue(returnValue, ds_aggregation);
	}
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_InitObjects = async function () {
    $c.gus.cfInitObjects(tbl_table1,null);

    //해당 컴포넌트만 삭제가 안되므로 수종삭제로직 추가.
    ed_acctDeptCd.setValue("");

    ica_stdYm.setValue(scwin.strFromDate);
	await scwin.f_LoadVer();
};


//--------------------------------------------------------------------------
// 그리드 데이터 엑셀로 다운
//--------------------------------------------------------------------------
scwin.f_runExcel = async function () {
    var totCnt      = ds_aggregation.getRowCount();
    var sheetTitle  = "계정별원가집계표";

    if( totCnt != 0){
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if(cfrm){
            //cfGridToExcel(gr_aggregation, sheetTitle, sheetTitle+".xls", 4+8+16);    
            const options = {
                fileName: sheetTitle,
                sheetName : sheetTitle,
                useSubTotal: true,
            };
            $c.data.downloadGridViewExcel(gr_aggregation, options);
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

//자회사 회계 시스템 추가에 따른 설정 
scwin.f_setCompanyInfo = async function () {
    //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
	if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
		scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
		scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
	}
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.rtnFlag = false;
    await scwin.f_PopUpCompanyInfo('T');

    scwin.interval01 = setInterval(async function() {
        if(scwin.rtnFlag == true) {
            clearInterval(scwin.interval01);

            if(ibx_txtCoClsCd.getValue() > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
                scwin.isSubCompany = true;
            }else{
                scwin.isSubCompany = false;
            }

            if('T' == scwin.privAdmin ||  !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
                $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company]);
            }else {
                $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);
            }
        }
    }, 30);
};

// 회사 입력 팝업 
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
    udc_comCode.setSelectId("retrieveDongbuGroupCompanyInfo");
    await udc_comCode.cfCommonPopUp(scwin.udc_comCode_callBackFunc,
        ed_coCd.getValue(), ed_coNm.getValue(),
        pWinCloseTF, null, null, null, null, 
        null, null, null, null, null);
};

scwin.udc_comCode_callBackFunc = async function (rtnList) {
    // SET
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }

        ed_coCd.setValue(rtnList[0]);   // 코드
        ed_coNm.setValue(rtnList[5]);   // 회사명
        ibx_txtCoClsCd.setValue(rtnList[1]);	// 회사구분 
    } else {
        ed_coCd.setValue("");   // 코드
        ed_coNm.setValue("");   // 회사명
        ibx_txtCoClsCd.setValue("");
    }

    scwin.rtnFlag = true;
}; 


scwin.ica_stdYm_onblur = async function (e) {
    await scwin.f_LoadVer();
};

scwin.lc_acctDeptCd_onchange = function (info) {
    if ($c.gus.cfIsNull(lc_acctDeptCd.getValue())) {
        return;
    }
	scwin.f_Retrieve();
};



scwin.ddd_onclick = function (e) {
    debugger;
};


scwin.udc_acctCdFrom_onclickEvent = async function (e) {
    await scwin.f_openPopUp(udc_acctCdFrom,'3',ed_acctCdFrom,ed_acctCdFromNm,'F');
};

scwin.udc_acctCdTo_onclickEvent = async function (e) {
    await scwin.f_openPopUp(udc_acctCdTo,'3',ed_acctCdTo,ed_acctCdToNm,'F');
};

