scwin.gr_aggregation_oncellclick = async function (rowIndex, columnIndex, columnId) {

    /*
    //to-do 일반행이 아니면(소계, 합계등) 스킵처리
    var ilevel = gr_aggregation.VirtualString(Row,"level")
	if ( ilevel > 0 ) {
        return
    }
    */

    //당월미확정
	if(columnId=="thisRsltsAmt") {
		if (ds_aggregation.getCellData(rowIndex,"thisRsltsAmt") != "0") {
			await scwin.f_detail(rowIndex,"2",0);
		}
	}
    //당월확정
    else if (columnId=="thisPlanAmt") {
			await scwin.f_detail(rowIndex,"1",0);
	}
    //전월미확정
    else if(columnId=="bfyyThisAmt"){
		if (ds_aggregation.getCellData(rowIndex,"bfyyThisAmt") != "0") {
			await scwin.f_detail(rowIndex,"2",-1);
		}
	}
};

